<script setup lang="ts">
import { Settings, CheckCircle2, Globe, Phone, Mail, MapPin, Instagram, Youtube, Facebook, Save, Loader2, AlertCircle, ShieldCheck, Layout
} from 'lucide-vue-next';
definePageMeta({ layout: 'admin', middleware: 'admin-only' })
useHead({ title: 'Pengaturan Situs - Admin PesantrenKu' });
const { data: settingsData, refresh } = await useFetch('/api/settings')
const loading = ref(false)
const successMsg = ref('') const settingsMap = computed(() => { const map: Record<string, string> = {} for (const s of (settingsData.value || []) as any[]) { map[s.key] = s.value } return map
});
const form = reactive({ site_name: '', site_tagline: '', contact_phone: '', contact_email: '', contact_address: '', social_instagram: '', social_youtube: '', social_facebook: '',
}) watchEffect(() => { const m = settingsMap.value form.site_name = m.site_name || '' form.site_tagline = m.site_tagline || '' form.contact_phone = m.contact_phone || '' form.contact_email = m.contact_email || '' form.contact_address = m.contact_address || '' form.social_instagram = m.social_instagram || '' form.social_youtube = m.social_youtube || '' form.social_facebook = m.social_facebook || ''
});
const handleSave = async () => { loading.value = true successMsg.value = '' try { const settings = Object.entries(form).map(([key, value]) => ({ key, value })) await $fetch('/api/settings', { method: 'PUT', body: { settings } }) successMsg.value = 'Pengaturan berhasil diperbarui!' refresh() setTimeout(() => successMsg.value = '', 4000) } catch { // Error handling } finally { loading.value = false }
}
</script>
