olute left-3.5 top-3 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" /> <UiInput v-model="form.site_name" placeholder="Pesantren Madani" class="pl-10 h-11 border-muted/60 focus-visible:ring-primary rounded-xl font-bold" /> </div> </div> <div class="space-y-2"> <UiLabel class="text-[10px] font-bold uppercase tracking-widest text-muted-foreground ml-1">Tagline Singkat</UiLabel> <UiInput v-model="form.site_tagline" placeholder="Membangun Generasi Qur'ani" class="h-11 border-muted/60 focus-visible:ring-primary rounded-xl italic text-muted-foreground" /> </div> </div> </UiCardContent> </UiCard> <!-- Contact Info --> <UiCard class="border-0 shadow-lg shadow-black/5 bg-background rounded-xl overflow-hidden ring-1 ring-border/5"> <UiCardHeader class="pb-4 border-b border-border/10 bg-muted/5"> <UiCardTitle class="text-lg font-bold flex items-center gap-2 text-left"> <Phone class="size-5 text-primary" /> Informasi Hubung Kami </UiCardTitle> <p class="text-[10px] uppercase tracking-widest font-bold text-muted-foreground text-left">Kontak Resmi & Alamat Fisik</p> </UiCardHeader> <UiCardContent class="p-8 space-y-6"> <div class="grid grid-cols-1 md:grid-cols-2 gap-6"> <div class="space-y-2"> <UiLabel class="text-[10px] font-bold uppercase tracking-widest text-muted-foreground ml-1">Nomor Telepon / WhatsApp</UiLabel> <div class="relative group"> <Phone class="absolute left-3.5 top-3 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" /> <UiInput v-model="form.contact_phone" placeholder="+62 8..." class="pl-10 h-11 border-muted/60 focus-visible:ring-primary rounded-xl font-mono" /> </div> </div> <div class="space-y-2"> <UiLabel class="text-[10px] font-bold uppercase tracking-widest text-muted-foreground ml-1">Email Resmi</UiLabel> <div class="relative group"> <Mail class="absolute left-3.5 top-3 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" /> <UiInput v-model="form.contact_email" placeholder="info@pesantren.com" class="pl-10 h-11 border-muted/60 focus-visible:ring-primary rounded-xl font-bold" /> </div> </div> </div> <div class="space-y-2 text-left"> <UiLabel class="text-[10px] font-bold uppercase tracking-widest text-muted-foreground ml-1">Alamat Lengkap</UiLabel> <div class="relative group"> <MapPin class="absolute left-3.5 top-3 w-4 h-4 text-muted-foreground group-focus-within:text-primary transition-colors" /> <UiTextarea v-model="form.contact_address" placeholder="Jl. Raya Utama No. 123..." class="pl-10 min-h-[100px] border-muted/60 focus-visible:ring-primary rounded-xl resize-none leading-relaxed" /> </div> </div> </UiCardContent> </UiCard> <!-- Social Media --> <UiCard class="border-0 shadow-lg shadow-black/5 bg-background rounded-xl overflow-hidden ring-1 ring-border/5"> <UiCardHeader class="pb-4 border-b border-border/10 bg-muted/5"> <UiCardTitle class="text-lg font-bold flex items-center gap-2"> <ShieldCheck class="size-5 text-primary" /> Media Sosial & Publikasi </UiCardTitle> <p class="text-[10px] uppercase tracking-widest font-bold text-muted-foreground">Tautan Eksternal Resmi</p> </UiCardHeader> <UiCardContent class="p-8 space-y-6"> <div class="grid grid-cols-1 md:grid-cols-3 gap-6"> <div class="space-y-2"> <UiLabel class="text-[10px] font-bold uppercase tracking-widest text-muted-foreground ml-1 flex items-center gap-2"> <Instagram class="size-3 text-pink-500" /> Instagram </UiLabel> <UiInput v-model="form.social_instagram" placeholder="https://instagram.com/..." class="h-11 border-muted/60 focus-visible:ring-primary rounded-xl text-xs" /> </div> <div class="space-y-2"> <UiLabel class="text-[10px] font-bold uppercase tracking-widest text-muted-foreground ml-1 flex items-center gap-2"> <Youtube class="size-3 text-red-500" /> YouTube </UiLabel> <UiInput v-model="form.social_youtube" placeholder="https://youtube.com/..." class="h-11 border-muted/60 focus-visible:ring-primary rounded-xl text-xs" /> </div> <div class="space-y-2"> <UiLabel class="text-[10px] font-bold uppercase tracking-widest text-muted-foreground ml-1 flex items-center gap-2"> <Facebook class="size-3 text-blue-600" /> Facebook </UiLabel> <UiInput v-model="form.social_facebook" placeholder="https://facebook.com/..." class="h-11 border-muted/60 focus-visible:ring-primary rounded-xl text-xs" /> </div> </div> </UiCardContent> </UiCard> </div> <!-- Info Footer --> <div class="p-6 bg-muted/20 rounded-xl border border-border/40 flex items-start gap-4"> <div class="size-10 rounded-xl bg-background shadow-sm flex items-center justify-center shrink-0 border border-border/40"> <AlertCircle class="size-5 text-amber-500" /> </div> <div class="space-y-1"> <h4 class="text-sm font-bold">Peringatan Keamanan</h4> <p class="text-xs text-muted-foreground leading-relaxed">Pembaruan data ini akan langsung berdampak pada seluruh halaman publik. Pastikan informasi yang Anda masukkan sudah valid dan sesuai dengan kebijakan pesantren.</p> </div> </div> </div>
